 80	            }),
 81	            status: t('In Progress'),
 82	            icon: <InProgressIcon />,
 83	          };
 84	
 85	    case DRPCStatus.Relocated:
 86	      return {
 87	        description: t('Relocated to cluster {{ preferredCluster }}', {
 88	          preferredCluster,
 89	        }),
 90	        status: t('Completed'),
 91	        icon: <GreenCheckCircleIcon />,
 92	      };
 93	
 94	    case DRPCStatus.FailingOver:
