101	      };
102	
103	    case DRPCStatus.FailedOver:
104	      if (isCleanupPending) {
105	        return replicationType === ReplicationType.ASYNC
106	          ? {
107	              description: t(
108	                'Clean up application resources on failed cluster {{ preferredCluster }} to start the replication.',
